class GlpiCommonAjaxController{constructor(){$(document).on("submit","form[data-ajax-submit]",e=>this.#e(e))}async#e(e){e.preventDefault();const t=$(e.target).closest("form");const a=this.#t(t);try{const e=await $.post({url:`${CFG_GLPI.root_doc}/GenericAjaxCrud`,data:a});this.#a(e);this.#s(e);this.#n(e,t);this.#r(e);this.#i();t.trigger("glpi-ajax-controller-submit-success",e)}catch(e){if(e.responseJSON!==undefined&&e.responseJSON.messages!==undefined){this.#a(e.responseJSON)}else{console.error(e);this.#a({messages:{error:[__("Unexpected error.")]}})}}}#t(e){const t=e.serializeArray();const a=document.activeElement;let s=null;if(a.tagName.toLowerCase()=="button"||a.tagName.toLowerCase()=="input"&&($(a).attr("type")=="submit"||$(a).attr("type")=="button")){s=$(a).prop("name")}else{s="update"}t.push({name:"_action",value:s});t.push({name:s,value:true});t.push({name:"itemtype",value:e.data("ajaxSubmitItemtype")});return $.param(t)}#a(e){if(!e.messages){return}if(e.messages.info!==undefined){e.messages.info.forEach(e=>glpi_toast_info(e))}if(e.messages.warning!==undefined){e.messages.warning.forEach(e=>glpi_toast_warning(e))}if(e.messages.error!==undefined){e.messages.error.forEach(e=>glpi_toast_error(e))}}#s(e){if(!e.friendlyname||!$("#header-friendlyname").length){return}$("#header-friendlyname").text(e.friendlyname)}#n(e,t){if(e.is_deleted===undefined){return}$("#navigationheader").toggleClass("asset-deleted",e.is_deleted);t.find("button[name=delete]").toggleClass("d-none",e.is_deleted);t.find("button[name=purge]").toggleClass("d-none",!e.is_deleted);t.find("button[name=restore]").toggleClass("d-none",!e.is_deleted)}#r(e){if(e.redirect===undefined){return}window.location=e.redirect}#i(){$("[data-glpi-tab-content]").each((e,t)=>{const a=$(t).hasClass("active");if(a){return}$(t).html("")})}}